rs": {},         "requestOptions": {}       },       "type": "n8n-nodes-base.n8n",       "typeVersion": 1,       "position": [         -448,         2064       ],       "id": "2d676fb6-4929-4f45-957b-9c24061e2317",       "name": "Fetch Workflows",       "credentials": {         "n8nApi": {           "id": "Lssk8mBfX4ReRipH",           "name": "n8n account"         }       }     },     {       "parameters": {         "options": {}       },       "type": "n8n-nodes-base.splitInBatches",       "typeVersion": 3,       "position": [         -224,         2064       ],       "id": "515b90f1-0f32-4628-85cd-d4223fe8e7ce",       "name": "Loop Workflows"     },     {       "parameters": {         "name": "={{ $json.fileName }}",         "driveId": {           "__rl": true,           "mode": "list",           "value": "My Drive"         },         "folderId": {           "__rl": true,           "mode": "id",           "value": "={{ $('Create Backup Folder').item.json.id }}"         },         "options": {}       },       "type": "n8n-nodes-base.googleDrive",       "typeVersion": 3,       "position": [         224,         2144       ],       "id": "6cd2e0d1-5bb4-406f-a7e1-6c475e3a4c51",       "name": "Upload to Drive",       "credentials": {         "googleDriveOAuth2Api": {           "id": "7rveCmWhR6Y9Hbo7",           "name": "Google Drive account"         }       }     },     {       "parameters": {         "jsCode": "// Get all backup folders and delete those older than 7 days
const parentFolderId = '1huM_c3I3CEF6eI9gesIvlkG5uIy4BgML';
const daysToKeep = 7;

try {
  // List all folders in the backup directory
  const options = {
    qs: {
      q: `'${parentFolderId}' in parents and mimeType='application/vnd.google-apps.folder' and name contains 'Workflow Backups'`,
      fields: 'files(id,name,createdTime)'
    }
  };

  const response = await this.helpers.httpRequestWithAuthentication.call(
    this,
    'googleDriveOAuth2Api',
    options
  );

  const folders = response.files || [];
  const cutoffDate = new Date();
  cutoffDate.setDate(cutoffDate.getDate() - daysToKeep);

  const foldersToDelete = folders.filter(folder => {
    const folderDate = new Date(folder.createdTime);
    return folderDate < cutoffDate;
  });

  console.log(`Found ${folders.length} backup folders, deleting ${foldersToDelete.length} old ones`);

  // Delete old folders
  for (const folder of foldersToDelete) {
    try {
      await this.helpers.httpRequestWithAuthentication.call(
        this,
        'googleDriveOAuth2Api',
        {
          method: 'DELETE',
          url: `https://www.googleapis.com/drive/v3/files/${folder.id}`
        }
      );
      console.log(`Deleted folder: ${folder.name} (${folder.id})`);
    } catch (error) {
      console.error(`Failed to delete folder ${folder.id}:`, error.message);
    }
  }

  return [{ json: { deleted: foldersToDelete.length, remaining: folders.length - foldersToDelete.length } }];

} catch (error) {
  console.error('Cleanup failed:', error.message);
  return [{ json: { error: error.message, status: 'cleanup_failed' } }];
